import type { UmbConditionControllerArguments, UmbExtensionCondition } from '@umbraco-cms/backoffice/extension-api';
import { UmbConditionBase } from '@umbraco-cms/backoffice/extension-registry';
import type { UmbControllerHost } from '@umbraco-cms/backoffice/controller-api';
import { ConfigService } from '@umbraco-forms/generated';
import { tryExecuteAndNotify } from '@umbraco-cms/backoffice/resources';
import type { SecurityOptionsConditionConfig } from './security-options-condition.config.js';

export class SecurityOptionsCondition
	extends UmbConditionBase<SecurityOptionsConditionConfig>
	implements UmbExtensionCondition
{
	constructor(
		host: UmbControllerHost,
		args: UmbConditionControllerArguments<SecurityOptionsConditionConfig>,
	) {
		super(host, args);

		tryExecuteAndNotify(this, ConfigService.getConfig()).then((response) => {			
			this.permitted = response.data !== undefined && this.config.match(response.data);
		});
	}
}

export default SecurityOptionsCondition;